@EndUserText.label: 'Column Store Table'
define table z_column_store_example {
  key client   : mandt;
  key doc_id   : vbeln;
      item_num : posnr;
      material : matnr;
      quantity : menge_d;
      amount   : netwr;
      currency : waerk;
}

@EndUserText.label: 'Row Store Table'
@AbapCatalog.sqlViewAppend: ''
define table z_row_store_example {
  key client      : mandt;
  key config_id   : char10;
      config_value: char100;
      description : char200;
}

-- Create secondary index on column store
CREATE INDEX z_sales_order_created
  ON sales_order (created_at) INDEX TYPE BTREE;

CREATE INDEX z_sales_order_org_status
  ON sales_order (sales_org, status, created_at) INDEX TYPE BTREE;

SELECT SCHEMA_NAME, TABLE_NAME, INDEX_NAME, INDEX_TYPE,
       RECORD_COUNT, INDEX_USAGE_COUNT
FROM INDEXES WHERE SCHEMA_NAME = 'SAPERP'
ORDER BY INDEX_USAGE_COUNT DESC;

-- Check HANA version and deployment type
SELECT HOST, START_TIME, VERSION, USAGE FROM M_DATABASE;

-- Memory per service
SELECT SERVICE_NAME, PHYSICAL_MEMORY_SIZE,
       LOGICAL_MEMORY_SIZE, ALLOCATION_LIMIT
FROM M_SERVICE_MEMORY;
